// RegisterUser creates a new user profile and inserts it into the database.
func RegisterUser(o orm.Ormer, username, displayName, email, department, role string) (*UserProfile, error) {
	user := &UserProfile{
		Username:    username,
		DisplayName: displayName,
		Email:       email,
		Department:  department,
		Role:        role,
	}

	_, err := o.Insert(user)
	if err != nil {
		return nil, err
	}

	return user, nil
}

// GenerateUserActivityReport creates an activity report for specified users.
func GenerateUserActivityReport(o orm.Ormer, usernames []string, actionTypeFilter string, startDate, endDate time.Time) ([]UserActivitySummary, error) {
	// Handle empty usernames slice
	if len(usernames) == 0 {
		return []UserActivitySummary{}, nil
	}

	// Build the placeholders for usernames
	placeholders := make([]string, len(usernames))
	args := make([]interface{}, len(usernames))
	for i, username := range usernames {
		placeholders[i] = "?"
		args[i] = username
	}

	// First, get user IDs for the given usernames
	userQuery := fmt.Sprintf("SELECT id FROM user_profile WHERE username IN (%s)", strings.Join(placeholders, ","))
	var userIds []int64
	_, err := o.Raw(userQuery, args...).QueryRows(&userIds)
	if err != nil {
		return nil, err
	}

	// Handle case where no users found
	if len(userIds) == 0 {
		return []UserActivitySummary{}, nil
	}

	// Build the placeholders for user IDs
	idPlaceholders := make([]string, len(userIds))
	idArgs := make([]interface{}, len(userIds))
	for i, id := range userIds {
		idPlaceholders[i] = "?"
		idArgs[i] = id
	}

	// Build the main query
	query := `SELECT u.display_name, a.action_type, COUNT(*) as total, 
			  SUM(CASE WHEN a.success THEN 1 ELSE 0 END) as success_count, 
			  AVG(a.duration_ms) as avg_duration
			  FROM user_activity a 
			  JOIN user_profile u ON a.user_id = u.id
			  WHERE a.user_id IN (` + strings.Join(idPlaceholders, ",") + `)` +
		` AND a.created_at BETWEEN ? AND ?`

	queryArgs := append(idArgs, startDate, endDate)

	// Add action type filter if provided
	if actionTypeFilter != "" {
		query += ` AND a.action_type = ?`
		queryArgs = append(queryArgs, actionTypeFilter)
	}

	query += ` GROUP BY u.display_name, a.action_type`

	// Execute the query
	var results []UserActivitySummary
	_, err = o.Raw(query, queryArgs...).QueryRows(&results)
	if err != nil {
		return nil, err
	}

	return results, nil
}

// GenerateDepartmentReport creates a summary report grouped by a specified field.
func GenerateDepartmentReport(o orm.Ormer, departments []string, groupByField string) ([]map[string]interface{}, error) {
	// Validate groupByField
	validFields := map[string]bool{
		"department":   true,
		"role":         true,
		"display_name": true,
	}

	if !validFields[groupByField] {
		return nil, fmt.Errorf("invalid groupByField: %s", groupByField)
	}

	// Build query based on groupByField
	columnName := groupByField
	if groupByField == "display_name" {
		columnName = "u.display_name"
	} else if groupByField == "department" {
		columnName = "u.department"
	} else if groupByField == "role" {
		columnName = "u.role"
	}

	query := fmt.Sprintf(`SELECT %s as group_value, COUNT(DISTINCT u.id) as user_count, COUNT(a.id) as total_activities
		FROM user_profile u
		LEFT JOIN user_activity a ON u.id = a.user_id`, columnName)

	var args []interface{}
	if len(departments) > 0 {
		query += " WHERE u.department IN (?" + strings.Repeat(",?", len(departments)-1) + ")"
		for _, dept := range departments {
			args = append(args, dept)
		}
	}

	query += fmt.Sprintf(" GROUP BY %s", columnName)

	// Execute query using struct instead of map
	var results []DepartmentReport
	_, err := o.Raw(query, args...).QueryRows(&results)
	if err != nil {
		return nil, err
	}

	// Convert to []map[string]interface{} for return
	report := make([]map[string]interface{}, len(results))
	for i, r := range results {
		report[i] = map[string]interface{}{
			"group_value":      r.GroupValue,
			"user_count":       r.UserCount,
			"total_activities": r.TotalActivities,
		}
	}

	return report, nil
}

