	RegisterUserFunc               = func(o orm.Ormer, username, displayName, email, department, role string) (*UserProfile, error) { return RegisterUser(o, username, displayName, email, department, role) }
	GenerateUserActivityReportFunc = func(o orm.Ormer, usernames []string, actionTypeFilter string, startDate, endDate time.Time) ([]UserActivitySummary, error) { return GenerateUserActivityReport(o, usernames, actionTypeFilter, startDate, endDate) }
	GenerateDepartmentReportFunc   = func(o orm.Ormer, departments []string, groupByField string) ([]map[string]interface{}, error) { return GenerateDepartmentReport(o, departments, groupByField) }
)

