// RegisterUser creates a new user profile and inserts it into the database.
func RegisterUser(o orm.Ormer, username, displayName, email, department, role string) (*UserProfile, error) {
	user := &UserProfile{
		Username:    username,
		DisplayName: displayName,
		Email:       email,
		Department:  department,
		Role:        role,
	}

	id, err := o.Insert(user)
	if err != nil {
		return nil, err
	}

	user.Id = id
	return user, nil
}

// GenerateUserActivityReport creates an activity report for specified users.
func GenerateUserActivityReport(o orm.Ormer, usernames []string, actionTypeFilter string, startDate, endDate time.Time) ([]UserActivitySummary, error) {
	if len(usernames) == 0 {
		return []UserActivitySummary{}, nil
	}

	// Build placeholders for usernames
	placeholders := make([]string, len(usernames))
	args := make([]interface{}, 0, len(usernames)+4)

	for i, username := range usernames {
		placeholders[i] = "?"
		args = append(args, username)
	}

	// Build the SQL query
	var sqlBuilder strings.Builder
	sqlBuilder.WriteString("SELECT u.display_name, a.action_type, COUNT(*) as total_actions, ")
	sqlBuilder.WriteString("SUM(CASE WHEN a.success THEN 1 ELSE 0 END) as success_count, ")
	sqlBuilder.WriteString("AVG(a.duration_ms) as avg_duration ")
	sqlBuilder.WriteString("FROM user_activity a JOIN user_profile u ON a.user_id = u.id ")
	sqlBuilder.WriteString(fmt.Sprintf("WHERE u.username IN (%s) ", strings.Join(placeholders, ",")))
	sqlBuilder.WriteString("AND a.created_at >= ? AND a.created_at <= ? ")

	args = append(args, startDate, endDate)

	// Add action type filter if provided
	if actionTypeFilter != "" {
		sqlBuilder.WriteString("AND a.action_type = ? ")
		args = append(args, actionTypeFilter)
	}

	sqlBuilder.WriteString("GROUP BY u.display_name, a.action_type")

	var summaries []UserActivitySummary
	_, err := o.Raw(sqlBuilder.String(), args).QueryRows(&summaries)
	if err != nil {
		return nil, err
	}

	return summaries, nil
}

// GenerateDepartmentReport creates a summary report grouped by a specified field.
func GenerateDepartmentReport(o orm.Ormer, departments []string, groupByField string) ([]map[string]interface{}, error) {
	if len(departments) == 0 {
		return []map[string]interface{}{}, nil
	}

	// Validate groupByField
	validFields := map[string]bool{
		"department":   true,
		"role":         true,
		"display_name": true,
	}
	if groupByField == "" || !validFields[groupByField] {
		return nil, fmt.Errorf("invalid groupByField: %s", groupByField)
	}

	// Build placeholders for departments
	placeholders := make([]string, len(departments))
	args := make([]interface{}, 0, len(departments))

	for i, dept := range departments {
		placeholders[i] = "?"
		args = append(args, dept)
	}

	// Build the SQL query based on groupByField
	var sqlBuilder strings.Builder
	sqlBuilder.WriteString("SELECT u.")
	sqlBuilder.WriteString(groupByField)
	sqlBuilder.WriteString(" as group_value, COUNT(DISTINCT u.id) as user_count, COUNT(a.id) as total_activities ")
	sqlBuilder.WriteString("FROM user_profile u LEFT JOIN user_activity a ON u.id = a.user_id ")
	sqlBuilder.WriteString(fmt.Sprintf("WHERE u.department IN (%s) ", strings.Join(placeholders, ",")))
	sqlBuilder.WriteString(fmt.Sprintf("GROUP BY u.%s", groupByField))

	var results []orm.Params
	num, err := o.Raw(sqlBuilder.String(), args).QueryRows(&results)
	if err != nil {
		return nil, err
	}

	// Convert []orm.Params to []map[string]interface{}
	reports := make([]map[string]interface{}, 0, num)
	for _, row := range results {
		report := make(map[string]interface{})
		for key, value := range row {
			report[key] = value
		}
		reports = append(reports, report)
	}

	return reports, nil
}

